parameters.jsonBody:
={
  "model": "claude-sonnet-4-6",
  "max_tokens": 2000,
  "system": "You are a global payroll ops expert. Given an employee termination, return a JSON array of jurisdiction-specific checklist items. Cover: final pay deadline per country/state, COBRA or statutory equivalent, pension/provident fund deregistration, PTO payout tax treatment, garnishment release notification, tax certificate issuance (IRP5/P45/W-2), direct deposit handling if deceased. Country rules — ZA: BCEA final pay by next regular payday + UI19; UK: contractual notice + P45; US: CA 72h voluntary / immediate involuntary, COBRA 14 days, state-specific; DE: contractual notice + final payslip; AU: Fair Work final pay within 7 days; AE: end-of-service gratuity. Schema per item: { item_type: 'final_pay'|'cobra'|'pension_dereg'|'pto_payout'|'garnishment_release'|'tax_certificate'|'direct_deposit_block'|'other', description: string, statutory_days: number (from last_working_day), owner_role: 'payroll'|'hr'|'finance'|'legal', evidence_required: string }. Return ONLY a JSON array. No prose.",
  "messages": [{ "role": "user", "content": {{ JSON.stringify({ employee: $json[0], termination: { type: $('Webhook').first().json.body.termination_type, notice_date: $('Webhook').first().json.body.notice_date, last_working_day: $('Webhook').first().json.body.last_working_day, has_garnishments: $('Webhook').first().json.body.has_garnishments, has_pension: $('Webhook').first().json.body.has_pension } }) }} }]
}

parameters.jsCode:
// Parse Sonnet output into structured checklist items with absolute deadlines.
const msg = $input.first().json;
const body = $('Webhook').first().json.body;
const employee = $('Fetch employee + country').first().json[0];

const rawText = msg.content?.[0]?.text ?? '';
const match = rawText.match(/\[[\s\S]*\]/);
if (!match) throw new Error('No JSON array in Sonnet output');
const items = JSON.parse(match[0]);

const lastDay = new Date(body.last_working_day);
const now = new Date();
const hoursToCutoff = (lastDay.getTime() - now.getTime()) / 3_600_000;
const urgent = hoursToCutoff < 2;

const enriched = items.map((item, i) => {
  const deadline = new Date(lastDay);
  deadline.setDate(deadline.getDate() + (Number(item.statutory_days) || 0));
  return {
    item_type: item.item_type,
    description: item.description,
    statutory_deadline: deadline.toISOString().slice(0, 10),
    owner_role: item.owner_role,
    position: i,
    status: 'pending',
  };
});

return [{
  json: {
    employee_id: employee.id,
    organization_id: employee.organization_id,
    termination_type: body.termination_type,
    notice_date: body.notice_date,
    last_working_day: body.last_working_day,
    final_pay_deadline: enriched.find(i => i.item_type === 'final_pay')?.statutory_deadline ?? body.last_working_day,
    checklist_items: enriched,
    urgent,
    hours_to_cutoff: Math.round(hoursToCutoff),
    country_iso: employee.countries?.iso_code,
  },
}];

// Attach termination_id to each checklist item for bulk insert.
const termRow = $input.first().json[0];
const structured = $('Structure checklist').first().json;
const items = structured.checklist_items.map((item) => ({
  ...item,
  termination_id: termRow.id,
}));
return [{ json: { termination: termRow, items, urgent: structured.urgent, hours_to_cutoff: structured.hours_to_cutoff, organization_id: structured.organization_id } }];
